SELECT LogimodaColli.Magazzino, LogimodaColli_AnagraficaItem.[Model Item No_], LogimodaColli.Collo, LogimodaColli.[Codice Articolo], "" AS Espr9, "PA" AS Espr1, 1 AS Espr2, LogimodaColli_AnagraficaItem.[Selling Season Code], LogimodaColli_AnagraficaItem.[Variable Group 02], LogimodaColli_AnagraficaItem.[Variable Group 01], LogimodaColli.Color_, LogimodaColli.Assortimento, 0 AS Espr3, 1 AS Espr4, LogimodaColli.quantita, 20 AS Espr5, "" AS Espr10, "" AS Espr11, "" AS Espr12, "" AS Espr13, "" AS Espr17, "" AS Espr14, "" AS Espr18, "" AS Espr15, "" AS Espr19, "" AS Espr16, "" AS Espr20, LogimodaColli_AnagraficaItem.[Model Code], LogimodaColli_AnagraficaItem.[Collection Code], LogimodaColli_AnagraficaItem.[Season Code], LogimodaColli_AnagraficaItem.[Line Code], 0 AS Espr6, LogimodaColli_AnagraficaItem.[Brand Code], "" AS Espr7, 0 AS Espr8, "" AS Espr21, "" AS Espr22, True AS Espr23
FROM LogimodaColli_AnagraficaItem RIGHT JOIN LogimodaColli ON (LogimodaColli_AnagraficaItem.[Variable Code 01] = LogimodaColli.Color_) AND (LogimodaColli_AnagraficaItem.[Model Item No_] = LogimodaColli.[Codice Articolo])
WHERE (((LogimodaColli_AnagraficaItem.[Model Item No_]) Is Null));

